/*selectInventoryList*/ SELECT CONCAT(WK.COMPKEY, WK.OWNERKY , WK.OWNERKY, WK.SKUMKEY) as ROWKEY ,WK.COMPKEY, WK.STOCKKY, MW.WHNAMLC as WAREKEY, MA.AREANAM as AREAKEY ,MZ.ZONENAM as ZONEKEY, ML.LOCANAM as LOCAKEY, WK.SUBSECT, WK.TRUNTYP ,WK.TRUNPID, WK.LOTNMKY, MO.OWNAMLC as OWNERKY, MS.SKUMKEY ,MS.SKUDESC, WK.VENDKEY, WK.SIRBCOD, WK.STOTQTY ,WK.SALLQTY, WK.SINBQTY, WK.SOUBQTY, WK.SBLOQTY ,MS.SUOMKEY, date_format(str_to_date(WK.PRODDAT, '%Y%m%d'), '%Y-%m-%d') as PRODDAT, WK.SHELIFE, WK.EXPIDAT , WK.LOTFRKY, WK.LOTAT01 ,WK.LOTAT02, WK.LOTAT03, WK.LOTAT04, WK.LOTAT05 ,WK.LOTAT06, WK.LOTAT07, WK.LOTAT08, WK.LOTAT09 ,WK.LOTAT10, WK.LOTAT11, WK.LOTAT12, WK.LOTAT13 ,WK.LOTAT14, WK.LOTAT15, WK.LOTAT16, WK.LOTAT17 ,WK.LOTAT18, WK.LOTAT19, WK.LOTAT20, MC.COMCDTX as STKSTAT ,WK.BLOCKID, WK.PHYSROW, WK.PHYSSEC, WK.PHYSFLO ,WK.RCVDCKY, WK.RCVDCIT, WK.TASKOKY, WK.TASKOIT ,WK.ADJSOKY, WK.ADJSOIT, WK.PHYSOKY, WK.PHYSOIT ,WK.STORFKY, WK.DOCCATE, WK.DOCTYPE, WK.CREDATE ,WK.CRETIME, WK.CREUSER, WK.LMODATE, WK.LMOTIME ,WK.LMOUSER, WK.INDIBZL, WK.INDIARC, WK.UPDTCHK FROM WSTKKY WK INNER JOIN MSKUWC MS ON WK.COMPKEY = MS.COMPKEY AND WK.WAREKEY = MS.WAREKEY AND WK.OWNERKY = MS.OWNERKY AND WK.SKUMKEY = MS.SKUMKEY INNER JOIN MWARMA MW ON WK.COMPKEY = MW.COMPKEY AND WK.WAREKEY = MW.WAREKEY INNER JOIN MOWRMA MO ON WK.COMPKEY = MO.COMPKEY AND WK.OWNERKY = MO.OWNERKY INNER JOIN V_MCODEM MC ON WK.COMPKEY = MC.COMPKEY AND WK.STKSTAT = MC.COMCDVL AND MC.COMCDKY = 'STKSTAT' INNER JOIN MAREMA MA ON WK.COMPKEY = MA.COMPKEY AND WK.WAREKEY = MA.WAREKEY AND WK.AREAKEY = MA.AREAKEY INNER JOIN MZONMA MZ ON WK.COMPKEY = MZ.COMPKEY AND WK.WAREKEY = MZ.WAREKEY AND WK.AREAKEY = MZ.AREAKEY AND WK.ZONEKEY = MZ.ZONEKEY INNER JOIN MLOCMA ML ON WK.COMPKEY = ML.COMPKEY AND WK.WAREKEY = ML.WAREKEY AND WK.AREAKEY = ML.AREAKEY AND WK.ZONEKEY = ML.ZONEKEY AND WK.LOCAKEY = ML.LOCAKEY WHERE WK.COMPKEY = #{compkey} AND (WK.STOTQTY != 0 or WK.SALLQTY != 0 or WK.SINBQTY != 0 or WK.SOUBQTY != 0 or WK.SBLOQTY != 0) AND WK.WAREKEY = #{warekey} AND WK.AREAKEY NOT IN ('SYS','SHP') AND WK.STOTQTY > 0
AND WK.WAREKEY = #{warekey}
AND WK.OWNERKY = #{ownerky}
AND WK.AREAKEY = #{areakey}
AND UPPER(WK.SKUMKEY) LIKE CONCAT('%', UPPER(#{skumkey}), '%')
AND UPPER(WK.SKUDESC) LIKE CONCAT('%', UPPER(#{skudesc}), '%')
AND WK.STKSTAT = #{stkstat}
ORDER BY WK.OWNERKY, WK.WAREKEY, WK.SKUMKEY, WK.SKUDESC, WK.STOCKKY DESC

/*selectGroupSkumKeyList*/ SELECT CONCAT(WK.COMPKEY, WK.WAREKEY ,WK.OWNERKY, WK.SKUMKEY) as ROWKEY ,WK.COMPKEY, MW.WHNAMLC as WAREKEY, MO.OWNAMLC as OWNERKY, MS.SKUMKEY ,MS.SKUDESC ,SUM(WK.STOTQTY) as STOTQTY, SUM(WK.SALLQTY) as SALLQTY ,SUM(WK.SINBQTY) as SINBQTY, SUM(WK.SOUBQTY) as SOUBQTY ,SUM(WK.SBLOQTY) as SBLOQTY ,MC.COMCDTX as STKSTAT, WK.VENDKEY, WK.SIRBCOD ,MS.SUOMKEY , ( SELECT SUM(STOTQTY) FROM WSTKKY WHERE COMPKEY = WK.COMPKEY AND WAREKEY = WK.WAREKEY AND OWNERKY = WK.OWNERKY AND SKUMKEY = WK.SKUMKEY AND AREAKEY = 'RCV' AND (WK.STOTQTY != 0 OR WK.SALLQTY != 0 OR WK.SINBQTY != 0 OR WK.SOUBQTY != 0 OR WK.SBLOQTY != 0) ) AS RCVSQTY ,( SELECT SUM(STOTQTY) FROM WSTKKY WHERE COMPKEY = WK.COMPKEY AND WAREKEY = WK.WAREKEY AND OWNERKY = WK.OWNERKY AND SKUMKEY = WK.SKUMKEY AND AREAKEY = 'STG' AND (WK.STOTQTY != 0 OR WK.SALLQTY != 0 OR WK.SINBQTY != 0 OR WK.SOUBQTY != 0 OR WK.SBLOQTY != 0) ) AS STGSQTY , ( SELECT SUM(STOTQTY) FROM WSTKKY WHERE COMPKEY = WK.COMPKEY AND WAREKEY = WK.WAREKEY AND OWNERKY = WK.OWNERKY AND SKUMKEY = WK.SKUMKEY AND AREAKEY = 'TAK' AND (WK.STOTQTY != 0 OR WK.SALLQTY != 0 OR WK.SINBQTY != 0 OR WK.SOUBQTY != 0 OR WK.SBLOQTY != 0) ) AS TAKSQTY FROM WSTKKY WK INNER JOIN MSKUWC MS on WK.COMPKEY = MS.COMPKEY and WK.WAREKEY = MS.WAREKEY and WK.OWNERKY = MS.OWNERKY and WK.SKUMKEY = MS.SKUMKEY INNER JOIN MWARMA MW ON WK.COMPKEY = MW.COMPKEY AND WK.WAREKEY = MW.WAREKEY INNER JOIN MOWRMA MO ON WK.COMPKEY = MO.COMPKEY AND WK.OWNERKY = MO.OWNERKY INNER JOIN V_MCODEM MC ON WK.COMPKEY = MC.COMPKEY AND WK.STKSTAT = MC.COMCDVL AND MC.COMCDKY = 'STKSTAT' INNER JOIN MLOCMA ML ON WK.COMPKEY = ML.COMPKEY AND WK.WAREKEY = ML.WAREKEY AND WK.AREAKEY = ML.AREAKEY AND WK.ZONEKEY = ML.ZONEKEY AND WK.LOCAKEY = ML.LOCAKEY WHERE WK.COMPKEY = #{compkey} AND (WK.STOTQTY != 0 or WK.SALLQTY != 0 or WK.SINBQTY != 0 or WK.SOUBQTY != 0 or WK.SBLOQTY != 0) AND WK.AREAKEY NOT IN ('SYS','SHP')
AND WK.WAREKEY = #{warekey}
AND WK.OWNERKY = #{ownerky}
AND WK.AREAKEY = #{areakey}
AND UPPER(WK.SKUMKEY) LIKE CONCAT('%', UPPER(#{skumkey}), '%')
AND UPPER(WK.SKUDESC) LIKE CONCAT('%', UPPER(#{skudesc}), '%')
AND WK.STKSTAT = #{stkstat}
GROUP BY WK.COMPKEY, MW.WHNAMLC ,MO.OWNAMLC, MS.SKUMKEY ,MS.SKUDESC, WK.VENDKEY, WK.SIRBCOD ,MS.SUOMKEY ,MC.COMCDTX

/*selectGroupLocationList*/ SELECT CONCAT(WK.COMPKEY, WK.OWNERKY, WK.SKUMKEY) as ROWKEY ,WK.COMPKEY, MW.WHNAMLC as WAREKEY,MA.AREANAM as AREAKEY ,MZ.ZONENAM as ZONEKEY, ML.LOCANAM as LOCAKEY, MO.OWNAMLC as OWNERKY, MS.SKUMKEY ,MS.SKUDESC, SUM(WK.STOTQTY) as STOTQTY ,SUM(WK.SALLQTY) as SALLQTY, SUM(WK.SINBQTY) as SINBQTY, SUM(WK.SOUBQTY) as SOUBQTY, SUM(WK.SBLOQTY) as SBLOQTY ,MS.SUOMKEY, WK.PRODDAT, WK.SHELIFE, WK.EXPIDAT,MC.COMCDTX as STKSTAT FROM WSTKKY WK INNER JOIN MSKUWC MS ON WK.COMPKEY = MS.COMPKEY AND WK.WAREKEY = MS.WAREKEY AND WK.OWNERKY = MS.OWNERKY AND WK.SKUMKEY = MS.SKUMKEY INNER JOIN MWARMA MW ON WK.COMPKEY = MW.COMPKEY AND WK.WAREKEY = MW.WAREKEY INNER JOIN MOWRMA MO ON WK.COMPKEY = MO.COMPKEY AND WK.OWNERKY = MO.OWNERKY INNER JOIN V_MCODEM MC ON WK.COMPKEY = MC.COMPKEY AND WK.STKSTAT = MC.COMCDVL AND MC.COMCDKY = 'STKSTAT' INNER JOIN MAREMA MA ON WK.COMPKEY = MA.COMPKEY AND WK.WAREKEY = MA.WAREKEY AND WK.AREAKEY = MA.AREAKEY INNER JOIN MZONMA MZ ON WK.COMPKEY = MZ.COMPKEY AND WK.WAREKEY = MZ.WAREKEY AND WK.AREAKEY = MZ.AREAKEY AND WK.ZONEKEY = MZ.ZONEKEY INNER JOIN MLOCMA ML ON WK.COMPKEY = ML.COMPKEY AND WK.WAREKEY = ML.WAREKEY AND WK.AREAKEY = ML.AREAKEY AND WK.ZONEKEY = ML.ZONEKEY AND WK.LOCAKEY = ML.LOCAKEY WHERE WK.COMPKEY = #{compkey} AND (WK.STOTQTY != 0 or WK.SALLQTY != 0 or WK.SINBQTY != 0 or WK.SOUBQTY != 0 or WK.SBLOQTY != 0) AND WK.AREAKEY NOT IN ('SYS','SHP')
AND WK.WAREKEY = #{warekey}
AND WK.OWNERKY = #{ownerky}
AND WK.AREAKEY = #{areakey}
AND UPPER(WK.SKUMKEY) LIKE CONCAT('%', UPPER(#{skumkey}), '%')
AND UPPER(WK.SKUDESC) LIKE CONCAT('%', UPPER(#{skudesc}), '%')
AND WK.STKSTAT = #{stkstat}
GROUP BY WK.COMPKEY, MW.WHNAMLC, MA.AREANAM, MZ.ZONENAM, ML.LOCANAM, MO.OWNAMLC, MS.SKUMKEY, MS.SKUDESC

/*selectRsnCodeList*/
SELECT
	MR.DOCTYPE, MR.RSNCODE, MR.RSNCDNM 
FROM
	MRSCMA MR
WHERE
	MR.COMPKEY = #{userData.compkey}
	AND MR.DOCCATE = #{doccate}
	AND MR.RSCATE1 = #{rscate1}

 		/*selectDoctypeSelectbox*/
 		SELECT
 			DOCTYPE, DOCTYNM
 		FROM
 			MDOCMA
 		WHERE
			COMPKEY = #{userData.compkey}
 			AND DOCCATE = #{doccate}
 			AND DOCTYPE IN ('310','320')

/*selectWstkkyList*/ SELECT CONCAT(WK.COMPKEY, WK.WAREKEY ,WK.OWNERKY, WK.SKUMKEY) as ROWKEY ,WK.COMPKEY, WK.STOCKKY, WK.WAREKEY, MW.WHNAMLC as WHNAMLC, WK.AREAKEY ,WK.ZONEKEY, WK.LOCAKEY, MA.AREANAM as AREANAM, MZ.ZONENAM as ZONENAM, ML.LOCANAM as LOCANAM ,WK.SUBSECT, WK.TRUNTYP ,WK.TRUNPID, WK.LOTNMKY ,WK.OWNERKY, MO.OWNAMLC as OWNAMLC, MS.SKUMKEY ,MS.SKUDESC, WK.VENDKEY, WK.SIRBCOD, WK.STOTQTY ,WK.SALLQTY, WK.SINBQTY, WK.SOUBQTY, WK.SBLOQTY ,MS.SUOMKEY, WK.PRODDAT, WK.SHELIFE, WK.EXPIDAT ,WK.RCVDCDT, WK.RCVFRDT, WK.LOTFRKY, WK.STKSTAT, MC.COMCDTX as COMCDTX ,WK.BLOCKID, WK.PHYSROW, WK.PHYSSEC, WK.PHYSFLO ,WK.RCVDCKY, WK.RCVDCIT, WK.TASKOKY, WK.TASKOIT ,WK.ADJSOKY, WK.ADJSOIT, WK.PHYSOKY, WK.PHYSOIT ,WK.STORFKY, WK.CREDATE, WK.CRETIME, WK.CREUSER ,WK.LMODATE, WK.LMOTIME ,WK.LMOUSER, WK.INDIBZL ,WK.INDIARC, WK.UPDTCHK , MR.COOTYPE as DOCTYPE, MR.COOTYNM ,MR.COOCATE as DOCCATE FROM WSTKKY WK INNER JOIN MSKUWC MS on WK.COMPKEY = MS.COMPKEY and WK.WAREKEY = MS.WAREKEY and WK.OWNERKY = MS.OWNERKY and WK.SKUMKEY = MS.SKUMKEY INNER JOIN MWARMA MW ON WK.COMPKEY = MW.COMPKEY AND WK.WAREKEY = MW.WAREKEY INNER JOIN MOWRMA MO ON WK.COMPKEY = MO.COMPKEY AND WK.OWNERKY = MO.OWNERKY INNER JOIN V_MCODEM MC ON WK.COMPKEY = MC.COMPKEY AND WK.STKSTAT = MC.COMCDVL AND MC.COMCDKY = 'STKSTAT' INNER JOIN MAREMA MA ON WK.COMPKEY = MA.COMPKEY AND WK.WAREKEY = MA.WAREKEY AND WK.AREAKEY = MA.AREAKEY INNER JOIN MZONMA MZ ON WK.COMPKEY = MZ.COMPKEY AND WK.WAREKEY = MZ.WAREKEY AND WK.AREAKEY = MZ.AREAKEY AND WK.ZONEKEY = MZ.ZONEKEY INNER JOIN MLOCMA ML ON WK.COMPKEY = ML.COMPKEY AND WK.WAREKEY = ML.WAREKEY AND WK.AREAKEY = ML.AREAKEY AND WK.ZONEKEY = ML.ZONEKEY AND WK.LOCAKEY = ML.LOCAKEY INNER JOIN MORDMA MR ON WK.COMPKEY = ML.COMPKEY AND WK.WAREKEY = ML.WAREKEY WHERE WK.COMPKEY = #{compkey} AND WK.STOTQTY > 0 AND WK.SALLQTY = 0 AND WK.SINBQTY = 0 AND WK.SOUBQTY = 0 AND WK.SBLOQTY = 0 AND WK.AREAKEY = 'STG' AND WK.STOCKKY NOT IN( SELECT STOCKKY FROM OEADJI WHERE OEINSST = 'NEW' ) AND WK.STOCKKY NOT IN( SELECT STOCKKY FROM OERETI WHERE OEINSST = 'NEW' )
AND WK.WAREKEY = #{warekey}
AND WK.OWNERKY = #{ownerky}
AND UPPER(WK.SKUMKEY) LIKE CONCAT('%', UPPER(#{skumkey}), '%')
AND UPPER(WK.SKUDESC) LIKE CONCAT('%', UPPER(#{skudesc}), '%')
AND WK.STKSTAT = #{stkstat}
AND MR.COOTYPE = #{cootype}

