/* insertOmi02Save */
INSERT
	INTO OEADJI
	 (
		 COMPKEY, OEADJKY, OEADJIT, OEINSDT
		 ,OEINSST, OEINSTM, RSNCODE, ADJSRMK
		 ,WAREKEY, DOCCATE, DOCTYPE, STOCKKY
		 ,AREAKEY, ZONEKEY, LOCAKEY, SUBSECT
		 ,TRUNTYP, TRUNPID ,LOTNMKY, OWNERKY
		 ,SKUMKEY, SKUDESC ,VENDKEY, SIRBCOD
		 ,STOTQTY, SALLQTY ,SINBQTY, SOUBQTY
		 ,SBLOQTY, SAVAQTY ,STKSTAT, SUOMKEY
		 ,RTODQTY, ATKSTAT, CREDATE, CRETIME
		 ,CREUSER, LMODATE, LMOTIME, LMOUSER

	)
VALUES
(
	#{userData.compkey},#{oeadjky},fn_om_oeadjit(#{userData.compkey},#{oeadjky}), date_format(NOW() , '%Y%m%d')
	,'NEW', date_format(NOW() , '%H%i%s'), #{rsncode}, #{adjsrmk}
	,#{warekey}, #{doccate}, #{doctype}, #{stockky}
	,#{areakey}, #{zonekey} ,#{locakey}, #{subsect}
	,#{truntyp}, #{trunpid} ,#{lotnmky}, #{ownerky}
	,#{skumkey}, #{skudesc} ,#{vendkey}, #{sirbcod}
	,#{stotqty}, #{sallqty} ,#{sinbqty}, #{soubqty}
	,#{sbloqty}, #{savaqty} ,#{stkstat}, #{suomkey}
	,#{rtodqty}, #{atkstat}, date_format(NOW() , '%Y%m%d'), date_format(NOW() , '%H%i%s')
	,#{userData.useract}, date_format(NOW() , '%Y%m%d'), date_format(NOW() , '%H%i%s')
	,#{userData.useract}
)

