/* selectOeadjiList */ SELECT CONCAT(OJ.COMPKEY, OJ.OWNERKY, OJ.SKUMKEY) as ROWKEY, OJ.COMPKEY, OJ.OEADJKY, OJ.OEADJIT, date_format(str_to_date(OJ.OEINSDT, '%Y%m%d'), '%Y-%m-%d') as OEINSDT ,date_format(str_to_date(OJ.OEINSTM, '%H%i%s'), '%H:%i:%s') as OEINSTM, MC1.COMCDTX as OEINSST ,MR.RSNCDNM as RSNCODE ,OJ.ADJSRMK ,MW.WHNAMLC as WAREKEY, OJ.DOCCATE, OJ.DOCTYPE, OJ.STOCKKY ,MA.AREANAM as AREAKEY, MZ.ZONENAM as ZONEKEY, ML.LOCANAM as LOCAKEY, OJ.SUBSECT ,OJ.TRUNTYP, OJ.TRUNPID, OJ.LOTNMKY, MO.OWNAMLC as OWNERKY ,MS.SKUMKEY, MS.SKUDESC, OJ.VENDKEY, OJ.SIRBCOD ,SUM(WS.STOTQTY) as STOTQTY , SUM(WS.SALLQTY) as SALLQTY, SUM(WS.SINBQTY) as SINBQTY, SUM(WS.SOUBQTY) as SOUBQTY ,SUM(WS.SBLOQTY) as SBLOQTY, MC2.COMCDTX AS STKSTAT, OJ.SUOMKEY ,OJ.RTODQTY, OJ.RTCFQTY, MC3.COMCDTX AS ATKSTAT, OJ.CREDATE ,OJ.CRETIME, OJ.CREUSER, OJ.LMODATE, OJ.LMOTIME ,OJ.LMOUSER, OJ.INDIBZL, OJ.INDIARC, OJ.UPDTCHK FROM OEADJI OJ INNER JOIN WSTKKY WS ON OJ.COMPKEY = WS.COMPKEY AND OJ.WAREKEY = WS.WAREKEY AND OJ.OWNERKY = WS.OWNERKY AND OJ.SKUMKEY = WS.SKUMKEY AND OJ.LOCAKEY = WS.LOCAKEY INNER JOIN MSKUWC MS ON OJ.COMPKEY = MS.COMPKEY AND OJ.WAREKEY = MS.WAREKEY AND OJ.OWNERKY = MS.OWNERKY AND OJ.SKUMKEY = MS.SKUMKEY INNER JOIN MRSCMA MR ON OJ.COMPKEY = MR.COMPKEY AND OJ.WAREKEY = MR.WAREKEY AND OJ.DOCCATE = MR.DOCCATE AND OJ.DOCTYPE = MR.DOCTYPE AND OJ.RSNCODE = MR.RSNCODE INNER JOIN MWARMA MW ON OJ.COMPKEY = MW.COMPKEY AND OJ.WAREKEY = MW.WAREKEY INNER JOIN MOWRMA MO ON OJ.COMPKEY = MO.COMPKEY AND OJ.OWNERKY = MO.OWNERKY INNER JOIN V_MCODEM MC1 ON OJ.COMPKEY = MC1.COMPKEY AND OJ.OEINSST = MC1.COMCDVL AND MC1.COMCDKY = 'OEINSST' INNER JOIN V_MCODEM MC2 ON OJ.COMPKEY = MC2.COMPKEY AND OJ.STKSTAT = MC2.COMCDVL AND MC2.COMCDKY = 'STKSTAT' INNER JOIN V_MCODEM MC3 ON OJ.COMPKEY = MC3.COMPKEY AND OJ.ATKSTAT = MC3.COMCDVL AND MC3.COMCDKY = 'STKSTAT' INNER JOIN MAREMA MA ON OJ.COMPKEY = MA.COMPKEY AND OJ.WAREKEY = MA.WAREKEY AND OJ.AREAKEY = MA.AREAKEY INNER JOIN MZONMA MZ ON OJ.COMPKEY = MZ.COMPKEY AND OJ.WAREKEY = MZ.WAREKEY AND OJ.AREAKEY = MZ.AREAKEY AND OJ.ZONEKEY = MZ.ZONEKEY INNER JOIN MLOCMA ML ON OJ.COMPKEY = ML.COMPKEY AND OJ.WAREKEY = ML.WAREKEY AND OJ.AREAKEY = ML.AREAKEY AND OJ.ZONEKEY = ML.ZONEKEY AND OJ.LOCAKEY = ML.LOCAKEY WHERE OJ.COMPKEY = #{compkey} AND (OJ.OEINSST = 'NEW' OR OJ.OEINSST = 'CMP')
AND OJ.WAREKEY = #{warekey}
AND OJ.OWNERKY = #{ownerky}
AND UPPER(OJ.SKUMKEY) LIKE CONCAT('%', UPPER(#{skumkey}), '%')
AND UPPER(OJ.SKUDESC) LIKE CONCAT('%', UPPER(#{skudesc}), '%')
AND OJ.OEINSST = #{oeinsst}
AND OJ.OEINSDT >= #{fromOeinsdt}
AND OJ.OEINSDT <= #{toOeinsdt}
GROUP BY OJ.OEADJKY, OJ.OEADJIT ORDER BY OJ.OEADJKY DESC, OJ.OEADJIT DESC

/*selectOeadjiCancelList*/ SELECT CONCAT(OJ.COMPKEY,OJ.WAREKEY ,OJ.OWNERKY, OJ.SKUMKEY) as ROWKEY, OJ.COMPKEY, OJ.OEADJKY, OJ.OEADJIT, date_format(str_to_date(OJ.OEINSDT, '%Y%m%d'), '%Y-%m-%d') as OEINSDT ,date_format(str_to_date(OJ.OEINSTM, '%H%i%s'), '%H:%i:%s') as OEINSTM, MC1.COMCDTX as OEINSST ,MR.RSNCDNM as ADCRSCD ,OJ.ADCRSNM ,MW.WHNAMLC as WAREKEY, OJ.DOCCATE, OJ.DOCTYPE, OJ.STOCKKY ,MA.AREANAM as AREAKEY, MZ.ZONENAM as ZONEKEY, ML.LOCANAM as LOCAKEY, OJ.SUBSECT ,OJ.TRUNTYP, OJ.TRUNPID, OJ.LOTNMKY, MO.OWNAMLC as OWNERKY ,MS.SKUMKEY, MS.SKUDESC, OJ.VENDKEY, OJ.SIRBCOD ,SUM(WS.STOTQTY) as STOTQTY , SUM(WS.SALLQTY) as SALLQTY, SUM(WS.SINBQTY) as SINBQTY, SUM(WS.SOUBQTY) as SOUBQTY ,SUM(WS.SBLOQTY) as SBLOQTY, MC2.COMCDTX AS STKSTAT, OJ.SUOMKEY ,OJ.RTODQTY, OJ.RTCFQTY, MC3.COMCDTX AS ATKSTAT, OJ.CREDATE ,OJ.CRETIME, OJ.CREUSER, OJ.LMODATE, OJ.LMOTIME ,OJ.LMOUSER, OJ.INDIBZL, OJ.INDIARC, OJ.UPDTCHK FROM OEADJI OJ LEFT JOIN WSTKKY WS ON OJ.COMPKEY = WS.COMPKEY AND OJ.WAREKEY = WS.WAREKEY AND OJ.OWNERKY = WS.OWNERKY AND OJ.SKUMKEY = WS.SKUMKEY AND OJ.LOCAKEY = WS.LOCAKEY LEFT JOIN MSKUWC MS ON OJ.COMPKEY = MS.COMPKEY AND OJ.WAREKEY = MS.WAREKEY AND OJ.OWNERKY = MS.OWNERKY AND OJ.SKUMKEY = MS.SKUMKEY LEFT JOIN MRSCMA MR ON OJ.COMPKEY = MR.COMPKEY AND OJ.WAREKEY = MR.WAREKEY AND OJ.DOCCATE = MR.DOCCATE AND OJ.DOCTYPE = MR.DOCTYPE AND OJ.ADCRSCD = MR.RSNCODE LEFT JOIN MWARMA MW ON OJ.COMPKEY = MW.COMPKEY AND OJ.WAREKEY = MW.WAREKEY LEFT JOIN MOWRMA MO ON OJ.COMPKEY = MO.COMPKEY AND OJ.OWNERKY = MO.OWNERKY LEFT JOIN V_MCODEM MC1 ON OJ.COMPKEY = MC1.COMPKEY AND OJ.OEINSST = MC1.COMCDVL AND MC1.COMCDKY = 'OEINSST' LEFT JOIN V_MCODEM MC2 ON OJ.COMPKEY = MC2.COMPKEY AND OJ.STKSTAT = MC2.COMCDVL AND MC2.COMCDKY = 'STKSTAT' LEFT JOIN V_MCODEM MC3 ON OJ.COMPKEY = MC3.COMPKEY AND OJ.ATKSTAT = MC3.COMCDVL AND MC3.COMCDKY = 'STKSTAT' LEFT JOIN MAREMA MA ON OJ.COMPKEY = MA.COMPKEY AND OJ.WAREKEY = MA.WAREKEY AND OJ.AREAKEY = MA.AREAKEY LEFT JOIN MZONMA MZ ON OJ.COMPKEY = MZ.COMPKEY AND OJ.WAREKEY = MZ.WAREKEY AND OJ.AREAKEY = MZ.AREAKEY AND OJ.ZONEKEY = MZ.ZONEKEY LEFT JOIN MLOCMA ML ON OJ.COMPKEY = ML.COMPKEY AND OJ.WAREKEY = ML.WAREKEY AND OJ.AREAKEY = ML.AREAKEY AND OJ.ZONEKEY = ML.ZONEKEY AND OJ.LOCAKEY = ML.LOCAKEY WHERE OJ.COMPKEY = #{compkey} AND OJ.OEINSST = 'CAN'
AND OJ.WAREKEY = #{warekey}
AND OJ.OWNERKY = #{ownerky}
AND UPPER(OJ.SKUMKEY) LIKE CONCAT('%', UPPER(#{skumkey}), '%')
AND UPPER(WK.SKUDESC) LIKE CONCAT('%', UPPER(#{skudesc}), '%')
AND OJ.OEINSDT = #{oeinsdt}
AND (
UPPER(OJ.ADCRSCD) LIKE CONCAT('%', UPPER(#{code}), '%')
)
AND OJ.OEINSDT >= #{fromOeinsdt}
AND OJ.OEINSDT <= #{toOeinsdt}
GROUP BY OJ.OEADJKY, OJ.OEADJIT ORDER BY OJ.OEADJKY DESC, OJ.OEADJIT DESC

/*selectOeadjiCancelListByNew*/ SELECT CONCAT(OJ.COMPKEY, OJ.OWNERKY, OJ.SKUMKEY) as ROWKEY, OJ.COMPKEY, OJ.OEADJKY, OJ.OEADJIT, date_format(str_to_date(OJ.OEINSDT, '%Y%m%d'), '%Y-%m-%d') as OEINSDT ,date_format(str_to_date(OJ.OEINSTM, '%H%i%s'), '%H:%i:%s') as OEINSTM, MC1.COMCDTX as OEINSST ,MR.RSNCDNM as RSNCODE ,OJ.ADJSRMK ,MW.WHNAMLC as WAREKEY, OJ.DOCCATE, OJ.DOCTYPE, OJ.STOCKKY ,OJ.AREAKEY, MA.AREANAM , OJ.ZONEKEY, MZ.ZONENAM, OJ.LOCAKEY, ML.LOCANAM, OJ.SUBSECT ,OJ.TRUNTYP, OJ.TRUNPID, OJ.LOTNMKY, MO.OWNAMLC, OJ.OWNERKY ,MS.SKUMKEY, MS.SKUDESC, OJ.VENDKEY, OJ.SIRBCOD ,SUM(WS.STOTQTY) as STOTQTY , SUM(WS.SALLQTY) as SALLQTY, SUM(WS.SINBQTY) as SINBQTY, SUM(WS.SOUBQTY) as SOUBQTY ,SUM(WS.SBLOQTY) as SBLOQTY, MC2.COMCDTX AS STKSTAT, OJ.SUOMKEY ,OJ.RTODQTY, OJ.RTCFQTY, MC3.COMCDTX AS ATKSTAT, OJ.CREDATE ,OJ.CRETIME, OJ.CREUSER, OJ.LMODATE, OJ.LMOTIME ,OJ.LMOUSER, OJ.INDIBZL, OJ.INDIARC, OJ.UPDTCHK FROM OEADJI OJ INNER JOIN WSTKKY WS ON OJ.COMPKEY = WS.COMPKEY AND OJ.WAREKEY = WS.WAREKEY AND OJ.OWNERKY = WS.OWNERKY AND OJ.SKUMKEY = WS.SKUMKEY AND OJ.LOCAKEY = WS.LOCAKEY INNER JOIN MSKUWC MS ON OJ.COMPKEY = MS.COMPKEY AND OJ.WAREKEY = MS.WAREKEY AND OJ.OWNERKY = MS.OWNERKY AND OJ.SKUMKEY = MS.SKUMKEY INNER JOIN MRSCMA MR ON OJ.COMPKEY = MR.COMPKEY AND OJ.WAREKEY = MR.WAREKEY AND OJ.DOCCATE = MR.DOCCATE AND OJ.DOCTYPE = MR.DOCTYPE AND OJ.RSNCODE = MR.RSNCODE INNER JOIN MWARMA MW ON OJ.COMPKEY = MW.COMPKEY AND OJ.WAREKEY = MW.WAREKEY INNER JOIN MOWRMA MO ON OJ.COMPKEY = MO.COMPKEY AND OJ.OWNERKY = MO.OWNERKY INNER JOIN V_MCODEM MC1 ON OJ.COMPKEY = MC1.COMPKEY AND OJ.OEINSST = MC1.COMCDVL AND MC1.COMCDKY = 'OEINSST' INNER JOIN V_MCODEM MC2 ON OJ.COMPKEY = MC2.COMPKEY AND OJ.STKSTAT = MC2.COMCDVL AND MC2.COMCDKY = 'STKSTAT' INNER JOIN V_MCODEM MC3 ON OJ.COMPKEY = MC3.COMPKEY AND OJ.ATKSTAT = MC3.COMCDVL AND MC3.COMCDKY = 'STKSTAT' INNER JOIN MAREMA MA ON OJ.COMPKEY = MA.COMPKEY AND OJ.WAREKEY = MA.WAREKEY AND OJ.AREAKEY = MA.AREAKEY INNER JOIN MZONMA MZ ON OJ.COMPKEY = MZ.COMPKEY AND OJ.WAREKEY = MZ.WAREKEY AND OJ.AREAKEY = MZ.AREAKEY AND OJ.ZONEKEY = MZ.ZONEKEY INNER JOIN MLOCMA ML ON OJ.COMPKEY = ML.COMPKEY AND OJ.WAREKEY = ML.WAREKEY AND OJ.AREAKEY = ML.AREAKEY AND OJ.ZONEKEY = ML.ZONEKEY AND OJ.LOCAKEY = ML.LOCAKEY WHERE OJ.COMPKEY = #{compkey} AND OJ.OEINSST = 'NEW'
AND OJ.WAREKEY = #{warekey}
AND OJ.OWNERKY = #{ownerky}
AND UPPER(OJ.SKUMKEY) LIKE CONCAT('%', UPPER(#{skumkey}), '%')
AND UPPER(WK.SKUDESC) LIKE CONCAT('%', UPPER(#{skudesc}), '%')
AND OJ.OEINSDT >= #{fromOeinsdt}
AND OJ.OEINSDT <= #{toOeinsdt}
GROUP BY OJ.OEADJKY, OJ.OEADJIT ORDER BY OJ.OEADJKY DESC, OJ.OEADJIT DESC

