UPDATE 
	OEADJI
SET
	ADCRSCD = #{adcrscd},
	ADCRSNM = #{adcrsnm},
	OEINSST = #{oeinsst},
	LMODATE = date_format(NOW() , '%Y%m%d'),
	LMOTIME = date_format(NOW() , '%H%i%s'),
	LMOUSER = #{userData.useract},
	UPDTCHK = #{updtchk}+1
WHERE
	COMPKEY = #{userData.compkey}
	AND OWNERKY = #{ownerky}
	AND STOCKKY = #{stockky}
	AND UPDTCHK = #{updtchk}
